34		float near_distance,
35		float plane_z,
36		float aperture_size,
37		Foveation foveation,
38		Lens lens,
39		BoundingBox train_aabb,
40		const uint8_t* __restrict__ density_grid,
41		uint32_t min_mip,
42		uint32_t max_mip,
43		float cone_angle_constant,
44		Buffer2DView<const vec4> envmap,
45		vec4* __restrict__ frame_buffer,
46		float* __restrict__ depth_buffer,
47		Buffer2DView<const uint8_t> hidden_area_mask,
48		Buffer2DView<const vec2> distortion,
49		ERenderMode render_mode,
50		const network_precision_t* __restrict__ params,
51		const float* __restrict__ extra_dims,
52		ENerfActivation density_activation,
53		ENerfActivation rgb_activation,
54		float min_transmittance,
55		bool train_in_linear_colors,
56		bool surface_rendering,
57		float surface_rendering_threshold
58	) {
59		uint32_t x = threadIdx.x + blockDim.x * blockIdx.x;
60		uint32_t y = threadIdx.y + blockDim.y * blockIdx.y;
61	
62		bool valid = x < resolution.x && y < resolution.y;
63		uint32_t idx = x + resolution.x * y;
64	
65		vec2 pixel_offset = ld_random_pixel_offset(snap_to_pixel_centers ? 0 : sample_index);
66		vec2 uv = vec2{(float)x + pixel_offset.x, (float)y + pixel_offset.y} / vec2(resolution);
67		mat4x3 camera =
68			get_xform_given_rolling_shutter({camera_matrix0, camera_matrix1}, rolling_shutter, uv, ld_random_val(sample_index, idx * 72239731));
69	
70		Ray ray = uv_to_ray(
71			sample_index,
